--DROP TABLE IF EXISTS PROFILES;
CREATE TABLE IF NOT EXISTS PROFILES (
        MODULETYPE      TEXT NOT NULL,
        PROFILENAME     TEXT NOT NULL,
        ALLVALUES       BLOB,
        PRIMARY KEY("MODULETYPE","PROFILENAME")
);
DELETE FROM PROFILES WHERE PROFILENAME in('demo','LRGB-60s','default');





--DROP TABLE IF EXISTS CONFIGURATIONS;
CREATE TABLE IF NOT EXISTS CONFIGURATIONS (
        CONFIGNAME     TEXT NOT NULL,
        MODULELABEL     TEXT NOT NULL,
        MODULETYPE     TEXT NOT NULL,
        PROFILENAME    TEXT NOT NULL,
        PRIMARY KEY("CONFIGNAME","MODULELABEL")
);
DELETE FROM CONFIGURATIONS WHERE PROFILENAME in ('demo','default');




--DROP TABLE IF EXISTS INDICONFIGURATIONS;
CREATE TABLE IF NOT EXISTS INDICONFIGURATIONS (
        CONFIGNAME     TEXT NOT NULL,
        DRIVERS     TEXT NOT NULL,
        PRIMARY KEY("CONFIGNAME","DRIVERS")
);



CREATE TABLE IF NOT EXISTS CATALOGS (
        CATALOG TEXT NOT NULL,
        CODE TEXT NOT NULL,
        RA REAL NOT NULL,
        NS TEXT NOT NULL,
        DEC REAL NOT NULL,
        DIAM REAL,
        MAG REAL,
        NAME TEXT,
        ALIAS TEXT,
        PRIMARY KEY("CATALOG","CODE","RA")
);
CREATE TABLE IF NOT EXISTS USERS (
        LOGIN     TEXT NOT NULL,
        PW     TEXT NOT NULL,
        GRANT     TEXT NOT NULL, -- 0 : readOnly / 1 : read/write
        PRIMARY KEY("LOGIN")
);
